module top_module(
  input [31:0] in,
  input [4:0] shift_amount,
  input [1:0] shift_type,
  output reg [31:0] inverted_out
);always @(*) begin
  case (shift_type)
    2'b00: inverted_out = in << shift_amount;
    2'b01: inverted_out = in >> shift_amount;
    2'b10: inverted_out = $signed(in) >>> shift_amount;
    default: inverted_out = in;
  endcase
end

endmodule
